{"file_path": "/home/someone/Documents/eagle-point/104/repo/src/common/filters/global-exception.filter.ts", "content": "import {
  ExceptionFilter,
  Catch,
  ArgumentsHost,
  HttpException,
  HttpStatus,
} from '@nestjs/common';
import { Request, Response } from 'express';

@Catch()
export class GlobalExceptionFilter implements ExceptionFilter {
  catch(exception: unknown, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();
    const traceId = (request as any).traceId || 'unknown';

    let status = HttpStatus.INTERNAL_SERVER_ERROR;
    let code = 'INTERNAL_ERROR';
    let message = 'Internal server error';

    if (exception instanceof HttpException) {
      status = exception.getStatus();
      const exResponse = exception.getResponse();
      if (typeof exResponse === 'object' && exResponse !== null) {
        const r = exResponse as any;
        code = r.code || this.statusToCode(status);
        message = r.message || exception.message;
        if (Array.isArray(message)) {
          message = message.join('; ');
        }
      } else {
        code = this.statusToCode(status);
        message = exception.message;
      }
    }

    response.status(status).json({
      statusCode: status,
      code,
      message,
      traceId,
    });
  }

  private statusToCode(status: number): string {
    switch (status) {
      case 400: return 'VALIDATION_ERROR';
      case 401: return 'UNAUTHORIZED';
      case 403: return 'FORBIDDEN';
      case 404: return 'NOT_FOUND';
      case 409: return 'CONFLICT';
      default: return 'INTERNAL_ERROR';
    }
  }
}
"}

