181	  @Cron(CronExpression.EVERY_HOUR)
182	  async recomputeAllScores(): Promise<void> {
183	    this.logger.log('Recomputing all data quality scores');
184	    for (const entityType of ALL_ENTITY_TYPES) {
185	      try {
186	        await this.computeScore(entityType);
187	      } catch (err) {
188	        this.logger.error(
189	          `Failed to compute score for ${entityType}: ${err.message}`,
190	        );
191	      }
192	    }
193	  }
194	
195	  @Cron(CronExpression.EVERY_HOUR)
196	  async checkFreshness(): Promise<void> {
197	    const thresholdHours =
198	      this.configService.get<number>('stalenessThresholdHours') || 24;
199	
200	    for (const entityType of ALL_ENTITY_TYPES) {
201	      try {
202	        const tableName = ENTITY_TABLE_MAP[entityType];
203	        const result = await this.dataSource.query(`
204	          SELECT GREATEST(
205	            MAX(CASE WHEN EXISTS (
206	              SELECT 1 FROM information_schema.columns
207	              WHERE table_name = '${tableName}' AND column_name = 'updated_at'
208	            ) THEN updated_at ELSE NULL END),
209	            MAX(created_at)
210	          ) as last_activity
211	          FROM "${tableName}"
212	        `);
213	
214	        const lastActivity = result[0]?.last_activity;
215	        if (!lastActivity) continue;
216	
217	        const hoursSinceActivity =
218	          (Date.now() - new Date(lastActivity).getTime()) / (1000 * 60 * 60);
219	
220	        if (hoursSinceActivity > thresholdHours) {
221	          await this.notificationsService.createForAdmins(
222	            'data_staleness',
223	            `Data for "${entityType}" has not been updated in ${Math.round(hoursSinceActivity)} hours (threshold: ${thresholdHours}h).`,
224	          );
225	        }
226	      } catch (err) {
227	        this.logger.error(
228	          `Freshness check failed for ${entityType}: ${err.message}`,
229	        );
230	      }
231	    }
232	  }
233	}
