1	import {
2	  Injectable,
3	  NotFoundException,
4	  BadRequestException,
5	} from '@nestjs/common';
6	import { InjectRepository } from '@nestjs/typeorm';
7	import { Repository } from 'typeorm';
8	import { StudyRoom } from './entities/study-room.entity';
9	import { Zone } from './entities/zone.entity';
10	import { Seat } from './entities/seat.entity';
11	import { SeatMapVersion } from './entities/seat-map-version.entity';
12	import { CreateRoomDto } from './dto/create-room.dto';
13	import { CreateZoneDto } from './dto/create-zone.dto';
14	import { CreateSeatDto } from './dto/create-seat.dto';
15	import { UpdateSeatDto } from './dto/update-seat.dto';
16	
17	@Injectable()
18	export class RoomsService {
19	  constructor(
20	    @InjectRepository(StudyRoom)
21	    private readonly roomRepo: Repository<StudyRoom>,
22	    @InjectRepository(Zone)
23	    private readonly zoneRepo: Repository<Zone>,
24	    @InjectRepository(Seat)
25	    private readonly seatRepo: Repository<Seat>,
26	    @InjectRepository(SeatMapVersion)
27	    private readonly seatMapVersionRepo: Repository<SeatMapVersion>,
28	  ) {}
29	
30	  /* ── Rooms ── */
31	
32	  async createRoom(dto: CreateRoomDto): Promise<StudyRoom> {
33	    const room = this.roomRepo.create(dto);
34	    return this.roomRepo.save(room);
35	  }
36	
37	  async findAllRooms(): Promise<StudyRoom[]> {
38	    return this.roomRepo.find({ relations: ['zones', 'zones.seats'] });
39	  }
40	
41	  async findRoomById(id: string): Promise<StudyRoom> {
42	    const room = await this.roomRepo.findOne({
43	      where: { id },
44	      relations: ['zones', 'zones.seats'],
45	    });
46	    if (!room) throw new NotFoundException(`Room ${id} not found`);
47	    return room;
48	  }
49	
50	  async updateRoom(id: string, dto: Partial<CreateRoomDto>): Promise<StudyRoom> {
51	    const room = await this.findRoomById(id);
52	    Object.assign(room, dto);
53	    return this.roomRepo.save(room);
54	  }
55	
56	  async deleteRoom(id: string): Promise<void> {
57	    const room = await this.findRoomById(id);
58	    await this.roomRepo.remove(room);
59	  }
60	
61	  /* ── Zones ── */
62	
63	  async createZone(roomId: string, dto: CreateZoneDto): Promise<Zone> {
64	    await this.findRoomById(roomId);
65	    const zone = this.zoneRepo.create({ ...dto, room_id: roomId });
66	    return this.zoneRepo.save(zone);
67	  }
68	
69	  async findZonesByRoom(roomId: string): Promise<Zone[]> {
70	    await this.findRoomById(roomId);
71	    return this.zoneRepo.find({
72	      where: { room_id: roomId },
73	      relations: ['seats'],
74	    });
75	  }
76	
77	  /* ── Seats ── */
78	
79	  async createSeat(zoneId: string, dto: CreateSeatDto): Promise<Seat> {
80	    const zone = await this.zoneRepo.findOne({ where: { id: zoneId } });
81	    if (!zone) throw new NotFoundException(`Zone ${zoneId} not found`);
82	    const seat = this.seatRepo.create({ ...dto, zone_id: zoneId });
83	    return this.seatRepo.save(seat);
84	  }
85	
86	  async findSeatsByZone(zoneId: string): Promise<Seat[]> {
87	    const zone = await this.zoneRepo.findOne({ where: { id: zoneId } });
88	    if (!zone) throw new NotFoundException(`Zone ${zoneId} not found`);
89	    return this.seatRepo.find({ where: { zone_id: zoneId } });
90	  }
91	
92	  async updateSeat(id: string, dto: UpdateSeatDto): Promise<Seat> {
93	    const seat = await this.seatRepo.findOne({ where: { id } });
94	    if (!seat) throw new NotFoundException(`Seat ${id} not found`);
95	    Object.assign(seat, dto);
96	    return this.seatRepo.save(seat);
97	  }
98	
99	  async deleteSeat(id: string): Promise<void> {
100	    const seat = await this.seatRepo.findOne({ where: { id } });
101	    if (!seat) throw new NotFoundException(`Seat ${id} not found`);
102	    await this.seatRepo.remove(seat);
103	  }
104	
105	  /* ── Seat-Map Versioning ── */
106	
107	  async publishSeatMap(
108	    roomId: string,
109	    changeNote: string,
110	    userId: string,
111	  ): Promise<SeatMapVersion> {
112	    const room = await this.roomRepo.findOne({
113	      where: { id: roomId },
114	      relations: ['zones', 'zones.seats'],
115	    });
116	    if (!room) throw new NotFoundException(`Room ${roomId} not found`);
117	
118	    // Build immutable snapshot
119	    const snapshot = {
120	      room: { id: room.id, name: room.name },
121	      zones: room.zones.map((z) => ({
122	        id: z.id,
123	        name: z.name,
124	        seats: z.seats.map((s) => ({
125	          id: s.id,
126	          label: s.label,
127	          power_outlet: s.power_outlet,
128	          quiet_zone: s.quiet_zone,
129	          ada_accessible: s.ada_accessible,
130	          status: s.status,
131	        })),
132	      })),
133	    };
134	
135	    // Determine next version number
136	    const latest = await this.seatMapVersionRepo.findOne({
137	      where: { room_id: roomId },
138	      order: { version_number: 'DESC' },
139	    });
140	    const nextVersion = latest ? latest.version_number + 1 : 1;
141	
142	    const version = this.seatMapVersionRepo.create({
143	      room_id: roomId,
144	      version_number: nextVersion,
145	      created_by: userId,
146	      change_note: changeNote,
147	      snapshot,
148	    });
149	
150	    return this.seatMapVersionRepo.save(version);
151	  }
152	
153	  async getVersions(roomId: string): Promise<SeatMapVersion[]> {
154	    await this.findRoomById(roomId);
155	    return this.seatMapVersionRepo.find({
156	      where: { room_id: roomId },
157	      order: { version_number: 'DESC' },
158	    });
159	  }
160	}
