35	  async createPromotion(dto: CreatePromotionDto): Promise<Promotion> {
36	    const promotion = this.promotionRepo.create({
37	      store_id: dto.storeId,
38	      name: dto.name,
39	      type: dto.type,
40	      priority: dto.priority,
41	      discount_type: dto.discountType,
