43	      min_order_cents: dto.minOrderCents ?? null,
44	      starts_at: dto.startsAt ? new Date(dto.startsAt) : null,
45	      ends_at: dto.endsAt ? new Date(dto.endsAt) : null,
46	      redemption_cap: dto.redemptionCap ?? null,
47	    });
48	    return this.promotionRepo.save(promotion);
49	  }
