51	  async createCoupon(dto: CreateCouponDto): Promise<Coupon> {
52	    const coupon = this.couponRepo.create({
53	      store_id: dto.storeId,
54	      code: dto.code,
55	      promotion_id: dto.promotionId,
56	      remaining_quantity: dto.remainingQuantity ?? null,
57	      starts_at: dto.startsAt ? new Date(dto.startsAt) : null,
58	      ends_at: dto.endsAt ? new Date(dto.endsAt) : null,
59	    });
60	    return this.couponRepo.save(coupon);
61	  }
