63	  async claimCoupon(code: string, userId: string): Promise<CouponClaim> {
64	    const coupon = await this.couponRepo.findOne({ where: { code } });
65	    if (!coupon) {
66	      throw new NotFoundException('Coupon not found');
67	    }
68	
69	    if (coupon.status !== CouponStatus.ACTIVE) {
70	      throw new BadRequestException(`Coupon is ${coupon.status}`);
71	    }
72	
73	    const now = new Date();
74	    if (coupon.starts_at && now < coupon.starts_at) {
75	      throw new BadRequestException('Coupon is not yet active');
76	    }
77	    if (coupon.ends_at && now > coupon.ends_at) {
78	      throw new BadRequestException('Coupon has expired');
79	    }
