async exportCsv(from?: string, to?: string): Promise<string> {
  const logs = await this.findAllForExport(from, to);

  const headers = ['id', 'actor_id', 'action', 'resource_type', 'resource_id', 'detail', 'trace_id', 'created_at'];
  const rows = logs.map(log => [
    log.id,
    log.actor_id,
    log.action,
    log.resource_type,
    log.resource_id || '',
    this.maskSensitiveFields(log.detail || ''),
    log.trace_id || '',
    log.created_at.toISOString(),
  ]);

  return [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
}

private maskSensitiveFields(detail: string): string {
  if (!detail) return detail;

  return detail
    .replace(/password_hash[^,\s]*/gi, 'password_hash:[REDACTED]')
    .replace(/password[^,\s]*/gi, 'password:[REDACTED]')
    .replace(/secret[^,\s]*/gi, 'secret:[REDACTED]')
    .replace(/key[^,\s]*/gi, 'key:[REDACTED]')
