15	@Injectable()
16	export class InventoryService {
17	  private readonly logger = new Logger(InventoryService.name);
18	
19	  constructor(
20	    @InjectRepository(InventoryLot)
21	    private readonly lotRepo: Repository<InventoryLot>,
22	    @InjectRepository(InventoryAdjustment)
23	    private readonly adjustmentRepo: Repository<InventoryAdjustment>,
24	    private readonly configService: ConfigService,
25	  ) {}
26	
27	  /* ── Lots ── */
28	
29	  async createLot(dto: CreateLotDto): Promise<InventoryLot> {
30	    const lot = this.lotRepo.create({
31	      sku_id: dto.skuId,
32	      batch_code: dto.batchCode,
33	      expiration_date: dto.expirationDate ?? null,
34	      quantity: dto.quantity,
35	    });
36	    return this.lotRepo.save(lot);
37	  }
38	
39	  async findAllLots(skuId?: string): Promise<InventoryLot[]> {
40	    const where: any = {};
41	    if (skuId) where.sku_id = skuId;
42	    return this.lotRepo.find({ where, relations: ['sku'] });
43	  }
44	
45	  async findLotById(id: string): Promise<InventoryLot> {
46	    const lot = await this.lotRepo.findOne({ where: { id }, relations: ['sku'] });
47	    if (!lot) throw new NotFoundException(`Lot ${id} not found`);
48	    return lot;
49	  }
50	
51	  async updateLot(
52	    id: string,
53	    updates: Partial<Pick<InventoryLot, 'batch_code' | 'expiration_date' | 'quantity'>>,
54	  ): Promise<InventoryLot> {
55	    const lot = await this.findLotById(id);
56	    Object.assign(lot, updates);
57	    return this.lotRepo.save(lot);
58	  }
59	
60	  /* ── Stock Adjustment ── */
61	
62	  async adjustStock(
63	    dto: AdjustStockDto,
64	    userId: string,
65	  ): Promise<{ adjustment: InventoryAdjustment; alreadyExisted: boolean }> {
66	    // Idempotency check
67	    const existing = await this.adjustmentRepo.findOne({
68	      where: { idempotency_key: dto.idempotencyKey },
69	    });
70	    if (existing) {
71	      return { adjustment: existing, alreadyExisted: true };
72	    }
73	
74	    const lot = await this.findLotById(dto.lotId);
75	    lot.quantity += dto.delta;
76	    await this.lotRepo.save(lot);
77	
78	    const adjustment = this.adjustmentRepo.create({
79	      lot_id: dto.lotId,
80	      delta: dto.delta,
81	      reason_code: dto.reasonCode,
82	      idempotency_key: dto.idempotencyKey,
83	      adjusted_by: userId,
84	    });
85	    const saved = await this.adjustmentRepo.save(adjustment);
86	
87	    // Check low stock threshold
88	    const threshold = this.configService.get<number>('lowStockThreshold', 10);
89	    if (lot.quantity < threshold) {
90	      this.logger.warn(
91	        `Low stock alert: Lot ${lot.id} (SKU ${lot.sku_id}) quantity is ${lot.quantity}, below threshold ${threshold}`,
92	      );
93	    }
94	
95	    return { adjustment: saved, alreadyExisted: false };
96	  }
97	
98	  /* ── Cron Jobs ── */
99	
100	  @Cron(CronExpression.EVERY_DAY_AT_MIDNIGHT)
101	  async checkExpiringLots(): Promise<void> {
102	    const sevenDaysFromNow = new Date();
103	    sevenDaysFromNow.setDate(sevenDaysFromNow.getDate() + 7);
104	    const dateStr = sevenDaysFromNow.toISOString().split('T')[0];
105	
106	    const expiringLots = await this.lotRepo.find({
107	      where: {
108	        expiration_date: LessThanOrEqual(dateStr),
109	      },
110	      relations: ['sku'],
111	    });
112	
113	    for (const lot of expiringLots) {
114	      if (lot.quantity > 0) {
115	        this.logger.warn(
116	          `Expiring lot alert: Lot ${lot.id} (batch ${lot.batch_code}) expires on ${lot.expiration_date} with ${lot.quantity} units remaining`,
117	        );
118	      }
119	    }
120	  }
121	
122	  @Cron(CronExpression.EVERY_10_MINUTES)
123	  async checkLowStock(): Promise<void> {
124	    const threshold = this.configService.get<number>('lowStockThreshold', 10);
125	    const lots = await this.lotRepo
126	      .createQueryBuilder('lot')
127	      .where('lot.quantity < :threshold', { threshold })
128	      .andWhere('lot.quantity > 0')
129	      .getMany();
130	
131	    for (const lot of lots) {
132	      this.logger.warn(
133	        `Low stock: Lot ${lot.id} (SKU ${lot.sku_id}) has ${lot.quantity} units`,
134	      );
135	    }
136	  }
